### Summary Generation

```rust
impl PrePublishSummary {
    pub fn generate(
        hits: &[SearchHit],
        encryption_config: &EncryptionConfig,
        secret_report: &ScanReport,
    ) -> Self {
        let mut workspaces: HashMap<String, WorkspaceSummary> = HashMap::new();
        let mut agents: HashMap<String, AgentSummary> = HashMap::new();
        let mut total_chars = 0;
        let mut dates: Vec<DateTime<Utc>> = Vec::new();

        for hit in hits {
            // Aggregate by workspace
            workspaces.entry(hit.workspace.clone())
                .or_insert_with(|| WorkspaceSummary::new(&hit.workspace))
                .add_hit(hit);

            // Aggregate by agent
            agents.entry(hit.agent.clone())
                .or_insert_with(|| AgentSummary::new(&hit.agent))
                .add_hit(hit);

            total_chars += hit.content.len();

            if let Some(ts) = hit.created_at {
                if let Some(dt) = DateTime::from_timestamp_millis(ts) {
                    dates.push(dt);
                }
            }
        }

        dates.sort();

        Self {
            total_conversations: count_unique_conversations(hits),
            total_messages: hits.len(),
            total_characters: total_chars,
            estimated_size_bytes: estimate_compressed_size(total_chars),
            earliest_timestamp: dates.first().cloned().unwrap_or_default(),
            latest_timestamp: dates.last().cloned().unwrap_or_default(),
            date_histogram: build_histogram(&dates),
            workspaces: workspaces.into_values().collect(),
            agents: agents.into_values().collect(),
            secret_scan: ScanReportSummary::from(secret_report),
            encryption_config: EncryptionSummary::from(encryption_config),
            key_slots: Vec::new(),  // Filled after key setup
        }
    }
}
```

